# Deprecation warning pattern used in internal libraries
import warnings


class ClaudeClient:
    def complete_v1(self, prompt: str, **kwargs):
        """Deprecated: use complete(messages=[...]) instead."""
        warnings.warn(
            "complete_v1() is deprecated and will be removed in acme-claude v2.0. "
            "Use complete(messages=[{'role': 'user', 'content': prompt}]) instead.",
            DeprecationWarning,
            stacklevel=2,   # points to the caller's line, not this library
        )
        return self.complete(
            messages=[{"role": "user", "content": prompt}],
            **kwargs,
        )

