# scripts/check_sdk_versions.py (runs in platform team CI)
import subprocess, json, sys
from packaging.version import Version

LIBRARIES = {
    "acme-claude": {"latest": "1.5.0", "min_supported": "1.3.0"},
    "acme-auth":   {"latest": "2.1.0", "min_supported": "2.0.0"},
    "acme-telemetry": {"latest": "1.4.0", "min_supported": "1.2.0"},
}

CONSUMER_REPOS = [
    "your-org/invoice-extractor",
    "your-org/doc-classifier",
]

drift = []
for repo in CONSUMER_REPOS:
    # Read pyproject.toml or requirements.txt from GitHub
    content = subprocess.check_output(
        ["gh", "api", f"repos/{repo}/contents/pyproject.toml", "--jq", ".content"],
        text=True,
    )
    import base64, tomllib
    pyproject = tomllib.loads(base64.b64decode(content).decode())
    deps = pyproject.get("project", {}).get("dependencies", [])
    for dep in deps:
        for lib, info in LIBRARIES.items():
            if dep.startswith(lib):
                # Parse pinned version lower bound
                # (simplified — real implementation uses packaging.requirements)
                pinned = dep.split(">=")[1].split(",")[0] if ">=" in dep else "unknown"
                if pinned != "unknown" and Version(pinned) < Version(info["min_supported"]):
                    drift.append({"repo": repo, "library": lib, "pinned": pinned, "min": info["min_supported"]})

if drift:
    print("Libraries below minimum supported version:")
    for d in drift:
        print(f"  {d['repo']}: {d['library']} pinned >= {d['pinned']} (min: {d['min']})")
    sys.exit(1)
